const row = items[0]?.json ?? {};

const parseJson = (value) => {
  try {
    return JSON.parse(String(value ?? '{}'));
  } catch {
    return {};
  }
};

const toInt = (value) => Number.parseInt(String(value ?? 0), 10) || 0;
const toFloat = (value) => Number(value ?? 0) || 0;
const formatList = (value, fallback) => Array.isArray(value) && value.length > 0 ? value.join('; ') : fallback;
const formatMap = (value, fallback) => {
  if (!value || typeof value !== 'object') {
    return fallback;
  }
  const entries = Object.entries(value).filter(([, count]) => Number(count) > 0);
  return entries.length > 0 ? entries.map(([name, count]) => `${name}=${count}`).join(', ') : fallback;
};

const logSummary = parseJson(row.stdout);
const day = row.local_day ?? logSummary.day_ref ?? 'n/d';
const success = toInt(row.success_count);
const failures = toInt(row.failure_count);
const total = toInt(row.total_events);
const rate = toFloat(row.failure_rate_pct).toFixed(2);
const critical = toInt(row.critical_count);
const webhookFailed = toInt(row.webhook_failed_count);
const peakHour = row.peak_hour ?? 'n/d';
const amount = row.success_amount ?? '0';
const emailDone = toInt(row.email_done_count);
const emailFailed = toInt(row.email_failed_count);
const emailPending = toInt(row.email_pending_backlog);
const totalUsers = toInt(row.total_users);
const totalChurches = toInt(row.total_churches);
const totalEventsCatalog = toInt(row.total_events_catalog);
const newUsers = toInt(row.new_users);
const newChurches = toInt(row.new_churches);
const newEvents = toInt(row.new_events);

const httpTotal = toInt(logSummary.http_requests_total);
const http2xx = toInt(logSummary.http_2xx);
const http3xx = toInt(logSummary.http_3xx);
const http4xx = toInt(logSummary.http_4xx);
const http5xx = toInt(logSummary.http_5xx);
const topPaths = formatList(logSummary.top_paths, 'n/d');
const errorPaths = formatList(logSummary.error_paths, 'nenhuma');
const errorServices = formatMap(logSummary.errors_by_service, 'nenhum');
const warnServices = formatMap(logSummary.warns_by_service, 'nenhum');
const totalErrorSignals = Object.values(logSummary.errors_by_service ?? {}).reduce((sum, value) => sum + toInt(value), 0);
const totalWarnSignals = Object.values(logSummary.warns_by_service ?? {}).reduce((sum, value) => sum + toInt(value), 0);
const logSummaryError = logSummary._meta_error ? `- observacao: resumo de logs incompleto (${logSummary._meta_error})` : null;

const messageLines = [
  `Resumo FeConect (${day})`,
  '',
  'Aplicacao:',
  `- ${httpTotal} requisicoes HTTP no dia`,
  `- status HTTP: ${http2xx} 2xx | ${http3xx} 3xx | ${http4xx} 4xx | ${http5xx} 5xx`,
  `- rotas mais acessadas: ${topPaths}`,
  `- rotas com 4xx/5xx: ${errorPaths}`,
  `- sinais em logs: ${totalErrorSignals} erros relevantes | ${totalWarnSignals} warnings`,
  `- servicos com erro: ${errorServices}`,
  `- servicos com warning: ${warnServices}`,
  '',
  'Financeiro e integracoes:',
  `- ${success} pagamentos confirmados/recebidos de ${total}`,
  `- ${failures} pagamentos nao ok | taxa de falha ${rate}%`,
  `- valor confirmado: R$ ${amount}`,
  `- ${webhookFailed} webhooks com falha | ${critical} criticos (3+ tentativas)`,
  `- emails: ${emailDone} processados | ${emailFailed} com falha | ${emailPending} pendentes`,
  `- pico operacional as ${peakHour}h`,
  '',
  'Contexto da base:',
  `- base atual: ${totalUsers} usuarios | ${totalChurches} igrejas | ${totalEventsCatalog} eventos`,
  `- criados no dia: ${newUsers} usuarios | ${newChurches} igrejas | ${newEvents} eventos`,
];

if (logSummaryError) {
  messageLines.push('', logSummaryError);
}

return [{
  json: {
    message: messageLines.join('\n'),
    summary: row,
    logSummary,
  },
}];
